import { useState, useEffect } from 'react';
import axios from 'axios';
import Upload from '../components/Upload';
import Summary from '../components/Summary';
import Quiz from '../components/Quiz';
import Chat from '../components/Chat';

const Dashboard = () => {
  const [documents, setDocuments] = useState([]);
  const [selectedDoc, setSelectedDoc] = useState(null);

  useEffect(() => {
    const fetchDocuments = async () => {
      const token = localStorage.getItem('token');
      if (token) {
        const res = await axios.get('http://localhost:5000/api/documents', { headers: { Authorization: `Bearer ${token}` } });
        setDocuments(res.data);
      }
    };
    fetchDocuments();
  }, []);

  return (
    <div className="container mx-auto p-4">
      <Upload onUpload={() => window.location.reload()} />
      <div className="mt-4">
        <h2 className="text-xl mb-2">Your Documents</h2>
        {documents.map(doc => (
          <div key={doc._id} className="border p-2 mb-2 cursor-pointer" onClick={() => setSelectedDoc(doc)}>
            {doc.filename}
          </div>
        ))}
      </div>
      {selectedDoc && (
        <div className="mt-4">
          <Summary docId={selectedDoc._id} />
          <Quiz docId={selectedDoc._id} />
          <Chat docId={selectedDoc._id} />
        </div>
      )}
    </div>
  );
};

export default Dashboard;
